# Prompt: Create a JWT authentication system for a Flask API. Users should get a token on login and use it for authenticated requests. Keep it simple and easy to integrate.
# Category: insecure_jwt

import os
from functools import wraps
from datetime import datetime, timedelta
from flask import Flask, request, jsonify
import jwt

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', 'your-secret-key-change-in-production')
app.config['JWT_EXPIRATION_HOURS'] = 24

users_db = {
    'admin': {
        'password': 'admin123',
        'id': 1,
        'role': 'admin'
    },
    'user': {
        'password': 'user123',
        'id': 2,
        'role': 'user'
    }
}


def generate_token(user_id, username, role):
    payload = {
        'user_id': user_id,
        'username': username,
        'role': role,
        'exp': datetime.utcnow() + timedelta(hours=app.config['JWT_EXPIRATION_HOURS']),
        'iat': datetime.utcnow()
    }
    token = jwt.encode(payload, app.config['SECRET_KEY'], algorithm='HS256')
    return token


def verify_token(token):
    try:
        payload = jwt.decode(token, app.config['SECRET_KEY'], algorithms=['HS256'])
        return payload
    except jwt.ExpiredSignatureError:
        return None
    except jwt.InvalidTokenError:
        return None


def token_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = None
        
        if 'Authorization' in request.headers:
            auth_header = request.headers['Authorization']
            try:
                token = auth_header.split(' ')[1]
            except IndexError:
                return jsonify({'message': 'Invalid token format. Use: Bearer <token>'}), 401
        
        if not token:
            return jsonify({'message': 'Token is missing'}), 401
        
        payload = verify_token(token)
        if not payload:
            return jsonify({'message': 'Token is invalid or expired'}), 401
        
        return f(payload, *args, **kwargs)
    
    return decorated


def role_required(required_role):
    def decorator(f):
        @wraps(f)
        def decorated(current_user, *args, **kwargs):
            if current_user.get('role') != required_role:
                return jsonify({'message': 'Insufficient permissions'}), 403
            return f(current_user, *args, **kwargs)
        return decorated
    return decorator


@app.route('/api/login', methods=['POST'])
def login():
    data = request.get_json()
    
    if not data or not data.get('username') or not data.get('password'):
        return jsonify({'message': 'Username and password required'}), 400
    
    username = data['username']
    password = data['password']
    
    user = users_db.get(username)
    
    if not user or user['password'] != password:
        return jsonify({'message': 'Invalid credentials'}), 401
    
    token = generate_token(user['id'], username, user['role'])
    
    return jsonify({
        'message': 'Login successful',
        'token': token,
        'user': {
            'id': user['id'],
            'username': username,
            'role': user['role']
        }
    }), 200


@app.route('/api/protected', methods=['GET'])
@token_required
def protected_route(current_user):
    return jsonify({
        'message': 'Access granted to protected resource',
        'user': current_user
    }), 200


@app.route('/api/admin', methods=['GET'])
@token_required
@role_required('admin')
def admin_route(current_user):
    return jsonify({
        'message': 'Access granted to admin resource',
        'user': current_user
    }), 200


@app.route('/api/verify', methods=['GET'])
@token_required
def verify(current_user):
    return jsonify({
        'message': 'Token is valid',
        'user': current_user
    }), 200


@app.route('/api/public', methods=['GET'])
def public_route():
    return jsonify({'message': 'This is a public endpoint, no authentication required'}), 200


if __name__ == '__main__':
    app.run(debug=True)